mapper.select:
    SELECT point_amount
	FROM point
	WHERE member_idx = #{member_idx}
	ORDER BY change_date DESC, point_id DESC -- 1순위: 최신 날짜, 2순위: 가장 나중에 생긴 데이터(PK)
	LIMIT 1;

mapper.update:
        UPDATE point
        SET    point_amount = point_amount + #{change_amount}
        WHERE  member_idx = #{member_idx} 
        ORDER BY change_date DESC, point_id DESC -- 1순위: 최신 날짜, 2순위: 가장 나중에 생긴 데이터(PK)
	    LIMIT 1;

mapper.insert:
INSERT INTO point ( member_idx, point_amount, change_amount, change_reason
) VALUES ( #{member_idx}, #{point_amount}, #{change_amount}, #{change_reason}
);

mapper.update:
UPDATE member
SET point_total = point_total + #{change_amount}
WHERE member_idx = #{member_idx}
